const data = {{workflowparams:data}};
const tableSi = (data && data.table_si) ? data.table_si : [];
const soSet = {}; const gdSet = {};
for (const r of tableSi) {
  if (!r) continue;
  if ((r.invoice_qty || 0) <= 0) continue;
  if (r.line_so_id) soSet[String(r.line_so_id)] = true;
  if (r.line_gd_id) gdSet[String(r.line_gd_id)] = true;
}
const soIds = Object.keys(soSet);
const gdReal = Object.keys(gdSet);
return {
  soIds: soIds.length ? soIds : ["0"],
  gdIdsSearch: gdReal.length ? gdReal : ["0"],
  gdIdsReal: gdReal
};

const rows = {{node:search_si_sopo.data.data}};
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);
const poSet = {}; const poNoSet = {}; let buyerOrg = ''; let sellerOrg = '';
for (const r of arr) {
  if (!r) continue;
  if (r.source_doc_id) poSet[String(r.source_doc_id)] = true;
  if (r.source_doc_no) poNoSet[String(r.source_doc_no)] = true;
  if (!buyerOrg && r.buyer_org_id) buyerOrg = String(r.buyer_org_id);
  if (!sellerOrg && r.seller_org_id) sellerOrg = String(r.seller_org_id);
}
return {
  poIds: Object.keys(poSet),
  poNos: Object.keys(poNoSet).join(', '),
  buyerOrg: buyerOrg || '0',
  sellerOrg: sellerOrg || '0'
};

const data = {{workflowparams:data}};
const saveAs = (data && data.si_status) ? data.si_status : '';
const autoConfirmed = (data && data.auto_pi_confirmed) ? data.auto_pi_confirmed : false;
const autoSkip = (data && data.auto_pi_skip) ? data.auto_pi_skip : false;
const poIds = {{node:code_si_link.data.poIds}} || [];
const buyerOrg = {{node:code_si_link.data.buyerOrg}} || '0';
const sellerOrg = {{node:code_si_link.data.sellerOrg}} || '0';
const itsRows = {{node:search_si_its.data.data}};
const itsArr = Array.isArray(itsRows) ? itsRows : (itsRows ? [itsRows] : []);
const autoCreatePi = itsArr.some(function (r) { return r && Number(r.auto_create_pi) === 1; });
const gdIds = {{node:code_si_srcids.data.gdIdsReal}} || [];
const gdgrRows = {{node:search_si_gdgr.data.data}};
const gdgrArr = Array.isArray(gdgrRows) ? gdgrRows : (gdgrRows ? [gdgrRows] : []);
const linkedGd = {};
for (const r of gdgrArr) { if (r && r.source_doc_id) linkedGd[String(r.source_doc_id)] = true; }
let gdCovered = true;
for (const g of gdIds) { if (!linkedGd[String(g)]) { gdCovered = false; break; } }

const internalLinked = (saveAs === 'Completed') && poIds.length > 0 && autoCreatePi;

let piConfirm = 0; let msg = ''; let doAutoPi = 0;
if (!internalLinked || autoSkip || !gdCovered) {
  piConfirm = 0;
} else if (!autoConfirmed) {
  piConfirm = 411;
  msg = 'This invoice is linked to an internal Purchase Order.<br><br>Auto-create the Purchase Invoice in the buyer organization when this invoice is completed?';
} else {
  doAutoPi = 1;
}
return { piConfirm: piConfirm, msg: msg, doAutoPi: doAutoPi, buyerOrg: buyerOrg, sellerOrg: sellerOrg };

let entry = {{node:code_node_2Pxz18TD.data.table}} || {{node:code_node_QaPUxa3s.data.entry}} || {{node:code_node_Z0Tcxb1v.data.entry}}

for (const [index, siLineItem] of entry.table_si.entries()) {
  siLineItem.customer_id = entry.customer_id || null;
  siLineItem.plant_id = entry.plant_id || null;
  siLineItem.payment_term_id = entry.si_payment_term_id || null;
  siLineItem.billing_state_id = entry.billing_address_state || null;
  siLineItem.billing_country_id = entry.billing_address_country || null;
  siLineItem.shipping_state_id = entry.shipping_address_state || null;
  siLineItem.shipping_country_id = entry.shipping_address_country || null;
  siLineItem.line_index = index + 1;
  siLineItem.agent_id = entry.sales_person_id;
  siLineItem.tax_amount = parseFloat(siLineItem.tax_amount || 0).toFixed(4);
  siLineItem.so_order_quantity = parseFloat(siLineItem.so_order_quantity || 0).toFixed(3);
  siLineItem.si_discount = parseFloat(siLineItem.si_discount || 0).toFixed(4);
  siLineItem.discount_amount = parseFloat(siLineItem.discount_amount || 0).toFixed(4);
  siLineItem.invoice_qty = parseFloat(siLineItem.invoice_qty || 0).toFixed(3);
  siLineItem.si_amount = parseFloat(siLineItem.si_amount || 0).toFixed(4);
  siLineItem.gross = parseFloat(siLineItem.gross || 0).toFixed(4);
  siLineItem.area_id = entry.si_area_id || '';
  siLineItem.agent_user_id = entry.agent_user_id || '';
}

entry.invoice_subtotal = parseFloat(entry.invoice_subtotal || 0).toFixed(4);
entry.invoice_total_discount = parseFloat(entry.invoice_total_discount || 0).toFixed(4);
entry.invoice_taxes_amount = parseFloat(entry.invoice_taxes_amount || 0).toFixed(4);
entry.invoice_total = parseFloat(entry.invoice_total || 0).toFixed(4);
entry.myr_total_amount = parseFloat(entry.myr_total_amount || 0).toFixed(4);
entry.outstanding_amount = parseFloat(entry.invoice_total || 0).toFixed(4);
entry.payment_status = entry.si_status === 'Draft' ? '' : 'Unpaid'

return { entry };

const soList = {{node:search_node_NDKdFanY.data.data}} || [];
const gdList = {{node:search_node_lTy219I0.data.data}} || [];
const data = {{node:code_node_JoF0YVzG.data.entry}};
let allErrors = [];

const roundTo3 = (value) => {
  return Math.round((parseFloat(value) || 0) * 1000) / 1000;
};

const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return "0.0000";
  return parseFloat(value).toFixed(3);
};


const validateInvoiceQuantities = (items, tableSi, docId, docIdKey, siLineIdKey, qtyKey) => {
  const filteredSI = tableSi.filter((item) => item[docIdKey] === docId);

  const errors = [];

  filteredSI.forEach((siItem) => {
    const originalItem = items.find(item => item.id === siItem[siLineIdKey]);

    if (originalItem) {
      const availableQty = roundTo3(originalItem[qtyKey]);
      const currentInvoicedQty = roundTo3(originalItem.invoice_qty);
      const newInvoiceQty = roundTo3(siItem.invoice_qty);
      const totalInvoicedQty = roundTo3(currentInvoicedQty + newInvoiceQty);

      if (totalInvoicedQty > availableQty) {
        errors.push({
          itemName: originalItem.item_id || originalItem.material_name || `Item ${originalItem.id}`,
        });
      }
    }
  });

  return errors;
};

const updateGoodsDelivery = (gdIds, tableSi) => {
  let gdUpdatedList = [];
  for(const gdID of gdIds) {
    const gdData = gdList.find(gd => gd.id === gdID)
    const gdItems = gdData.table_gd || [];

    const validationErrors = validateInvoiceQuantities(
      gdItems,
      tableSi,
      gdData.id,
      "line_gd_id",
      "gd_line_id",
      "gd_qty",
    );

    allErrors = [...allErrors, ...validationErrors];

    // Process GR items
    const { updatedItems, newSIStatus } = processItems(
      gdItems,
      tableSi,
      gdData.id,
      "line_gd_id",
      "gd_line_id",
      "gd_qty",
    );

    gdUpdatedList.push({
      gd_id: gdData.id,
      si_status: newSIStatus,
      table_gd: updatedItems
    })
  }

  return gdUpdatedList;
};

const updateSalesOrder = (soIds, tableSi) => {
  let soUpdatedList = [];
  for(const soID of soIds) {
    const soData = soList.find(so => so.id === soID)
    const soItems = soData.table_so || [];

    const validationErrors = validateInvoiceQuantities(
      soItems,
      tableSi,
      soData.id,
      "line_so_id",
      "so_line_id",
      "so_quantity"
    );

    allErrors = [...allErrors, ...validationErrors];

    const { updatedItems, newSIStatus } = processItems(
      soItems,
      tableSi,
      soData.id,
      "line_so_id",
      "so_line_id",
      "so_quantity",
    );

    soUpdatedList.push({
      so_id: soData.id,
      si_status: newSIStatus,
      table_so: updatedItems
    })
  }

  return soUpdatedList;
};


const processItems = (items, tableSi, docId, docIdKey, siLineIdKey, qtyKey) => {
  // Filter PI items for the current document
  const filteredSI = tableSi.filter((item) => item[docIdKey] === docId);

  // Filter items where item.id matches any siLineIdKey in filteredSI
  const filteredItems = items.filter((item) =>
    filteredSI.some((pi) => pi[siLineIdKey] === item.id),
  );

  // Initialize tracking
  let totalItems = items.length;
  let partiallyInvoicedItems = 0;
  let fullyInvoicedItems = 0;
  const updatedItems = items.map((item) => ({ ...item }));

  // Update invoice quantities
  filteredItems.forEach((filteredItem, filteredIndex) => {
    const originalIndex = updatedItems.findIndex(
      (item) => item.id === filteredItem.id,
    );

    if (originalIndex === -1) return;

    const itemQty = parseFloat(filteredItem[qtyKey] || 0);
    const piInvoicedQty = roundTo3(
      filteredSI[filteredIndex]?.invoice_qty
    );
    const currentInvoicedQty = roundTo3(
      updatedItems[originalIndex].invoice_qty
    );
    const totalInvoicedQty = roundTo3(currentInvoicedQty + piInvoicedQty);

    // Update invoice quantity
    updatedItems[originalIndex].invoice_qty = totalInvoicedQty;
  });

  for (const [index, item] of updatedItems.entries()) {
    if (roundTo3(item.invoice_qty) > 0) {
      partiallyInvoicedItems++;
      updatedItems[index].si_status = "Partially Invoiced";
      if (roundTo3(item.invoice_qty) >= roundTo3(item[qtyKey])) {
        fullyInvoicedItems++;
        updatedItems[index].si_status = "Fully Invoiced";
      }
    }
  }

  // Determine new PI status
  const allItemsComplete = fullyInvoicedItems === totalItems;
  const anyItemProcessing = partiallyInvoicedItems > 0;
  let newSIStatus = anyItemProcessing
    ? allItemsComplete
      ? "Fully Invoiced"
      : "Partially Invoiced"
    : "";

  return { updatedItems, newSIStatus };
};

const soIds = Array.isArray(data.so_id) ? data.so_id : [data.so_id];
let updatedGD = [];
if (data.gd_id.length > 0) {
  const gdIds = Array.isArray(data.gd_id) ? data.gd_id : [data.gd_id];
  const updatedGDData = updateGoodsDelivery(gdIds, data.table_si);
  updatedGD = updatedGDData.flat();
}
let updatedSO = updateSalesOrder(soIds, data.table_si);
updatedGD = updatedGD.filter(gd => gd.si_status === 'Fully Invoiced').map(gd => gd.gd_id)
updatedSO = updatedSO.filter(so => so.si_status === 'Fully Invoiced').map(so => so.so_id)

return {
  status: allErrors.length > 0 ? 'Failed' : 'Success', 
  allErrors, updatedGD, updatedSO
}

const errMsg = {{node:code_node_hHnkhdFI.data.allErrors}}.map(err => err.itemName).join(', ')

return {
 message: `${errMsg} invoice quantity exceed available invoice quantity.` 
}

const soList = {{node:search_node_NDKdFanY.data.data}} || [];
const gdList = {{node:search_node_lTy219I0.data.data}} || [];
const data = {{node:code_node_JoF0YVzG.data.entry}};

const roundTo3 = (value) => {
