const processItems = (items, tableSi, docId, docIdKey, siLineIdKey, qtyKey) => {
  // Filter SI items for the current document
  const filteredSI = tableSi.filter((item) => item[docIdKey] === docId);

  // Initialize tracking
  let totalItems = items.length;
  let partiallyInvoicedItems = 0;
  let fullyInvoicedItems = 0;

  // Update items using find() with id matching
  const updatedItems = items.map((item) => {
    const matchedSI = filteredSI.find(pi => pi[siLineIdKey] === item.id);

    if (matchedSI) {
      const piInvoicedQty = roundTo3(matchedSI.invoice_qty);
      const currentInvoicedQty = roundTo3(item.invoice_qty);
      const totalInvoicedQty = roundTo3(currentInvoicedQty + piInvoicedQty);

      const updatedItem = {
        ...item,
        invoice_qty: totalInvoicedQty
      };

      if (roundTo3(updatedItem.invoice_qty) > 0) {
          partiallyInvoicedItems++;
          updatedItem.si_status = "Partially Invoiced";
          if (roundTo3(updatedItem.invoice_qty) >= roundTo3(item[qtyKey] || 0)) {
            fullyInvoicedItems++;
            updatedItem.si_status = "Fully Invoiced";
          }
      }

      return updatedItem;
    }

    return { ...item };
  });

  // Determine new SI status
  const allItemsComplete = fullyInvoicedItems === totalItems;
  const anyItemProcessing = partiallyInvoicedItems > 0;
  let newSIStatus = anyItemProcessing
    ? allItemsComplete
      ? "Fully Invoiced"
      : "Partially Invoiced"
    : "";

  return { updatedItems, newSIStatus };
};

const soIds = Array.isArray(data.so_id) ? data.so_id : [data.so_id];
let updatedGD = [];
if (data.gd_id.length > 0) {
  const gdIds = Array.isArray(data.gd_id) ? data.gd_id : [data.gd_id];
  const updatedGDData = updateGoodsDelivery(gdIds, data.table_si);
  updatedGD = updatedGDData
}

const updatedSO = updateSalesOrder(soIds, data.table_si);

return {
  updatedGD, updatedSO
}

const r = {{node:wf_auto_pi.data}};
const d = (r && r.data && typeof r.data === 'object') ? r.data : r;
const code = d ? d.code : '';
const failed = (String(code) === '200') ? 0 : 1;
const msg = (d && (d.message || d.msg)) ? (d.message || d.msg) : 'The invoice was completed, but the linked Purchase Invoice could not be created automatically. Please create it manually.';
return { piTriggerFailed: failed, piMessage: msg };
